    },
    {
      "id": "BR-2",
      "rule": "Each Recipient within a Shipment must have a valid name, address, and phone number.",
      "invariant": true,
      "invariant_justification": "These are the minimum fields required to physically deliver goods and contact the recipient. Without them, a delivery attempt cannot be made.",
      "testable_assertion": "Creating a Recipient with a null or empty name, address, or phone number must be rejected at the aggregate boundary."
    },
    {
      "id": "BR-3",
      "rule": "Each Recipient within a Shipment must have a unique address. Duplicate addresses within the same Shipment are not permitted.",
      "invariant": true,
      "invariant_justification": "Two recipients at the same address on the same shipment is logically a single delivery stop. Allowing duplicates corrupts routing, billing, and delivery-attempt tracking.",
      "testable_assertion": "Adding a Recipient whose address matches an existing Recipient on the same Shipment must be rejected."
    },
    {
      "id": "BR-4",
      "rule": "Delivery preferences are optional per Recipient and default to standard delivery if not specified.",
      "invariant": false,
      "invariant_justification": "Default preferences are a business policy decision. The system must function without explicit preferences by falling back to standard delivery, but the specific defaults can change.",
      "testable_assertion": "A Recipient created without explicit delivery preferences must be assigned standard delivery defaults."
    },
