      "given": "A multi-recipient Shipment exists",
      "when": "An external partner API requests this Shipment's data and the partner has NOT opted into the new format",
      "then": "The response contains only the Primary Recipient in the legacy single-recipient format"
    },
    {
      "id": "AC-4",
      "given": "A Shipment with one Recipient",
      "when": "A user attempts to remove the last remaining Recipient",
      "then": "The operation is rejected with a validation error stating a Shipment must have at least one Recipient"
    },
    {
      "id": "AC-5",
      "given": "A multi-recipient Shipment",
      "when": "The Primary Recipient is removed",
      "then": "The system either rejects the removal or requires a new Primary to be designated in the same operation — the Shipment must never exist without a Primary Recipient"
    },
    {
      "id": "AC-6",
      "given": "A Shipment with two Recipients at different addresses",
      "when": "A third Recipient is added with the same address as an existing Recipient",
      "then": "The operation is rejected with a validation error indicating duplicate addresses"
    },
    {
      "id": "AC-7",
      "given": "A Recipient on a Shipment has no explicit delivery preferences set",
      "when": "The delivery is being planned or executed",
      "then": "Standard delivery defaults are applied for that Recipient"
    }
  ],

