    {
      "scenario": "A multi-recipient Shipment where all Recipients share the same phone number but different addresses",
      "expected_behavior": "This is valid — the same person can receive deliveries at multiple locations. Uniqueness is on address, not phone number."
    },
    {
      "scenario": "Partner API receives a webhook/push notification for a multi-recipient Shipment before opting into the new format",
      "expected_behavior": "The payload must be serialized in legacy format using the Primary Recipient only. No data about additional recipients should leak into the legacy format."
    },
    {
      "scenario": "Bulk migration is attempted on the ~2M existing shipments to add a 'primary' flag",
      "expected_behavior": "The single existing Recipient on each legacy shipment is automatically designated as Primary. This must be a backward-compatible, additive-only migration — no existing fields are altered or removed."
    },
